// Subject: Reset your password for {_productName}

import { PasswordResetBlock } from "@/components/email/block-shared";
import { dropboxTheme } from "@/components/email/theme-dropbox";

interface Props {
  _logoUrl?: string;
  _logoAlt?: string;
  resetHref?: string;
  expiresInMinutes?: number;
  _productName?: string;
}

export const AuthPasswordResetDropbox = ({
  resetHref = "#",
  expiresInMinutes = 60,
  _productName = "Dropbox",
}: Props) => (
  <PasswordResetBlock
    expiresInMinutes={expiresInMinutes}
    productName={_productName}
    resetHref={resetHref}
    theme={dropboxTheme}
  />
);

AuthPasswordResetDropbox.PreviewProps = {
  _logoAlt: "Dropbox",
  _logoUrl: "https://static.photos/business/320x80/2",
  _productName: "Dropbox",
  expiresInMinutes: 60,
  resetHref: "https://example.com/reset?token=abc123",
} satisfies Props;
